var e=[{id:`L2_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`복리후생이니, 생명수당 같은 건 관심 없어. 같이 싸우는 입장이니까, 서로의 방식을 존중해줘야 한다고 생각했을 뿐이야.`,JPN:`福利厚生や危険手当などに興味はない。共闘する立場だから、お互いのやり方を尊重しなければならないと思っているだけだ。`,ENG:`I don't care about employee welfare or combat pay. We're in this together, so I thought we should respect each other's style.`,TWN:`我對公司福利和危險津貼沒興趣。我們是一起戰鬥的夥伴，我只是覺得要尊重對方期望的方式。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`그러니 이번 한 번은 내가 양보할게.`,JPN:`だから、今回は私が一歩を譲る。`,ENG:`And in that sense, I'll yield just this once.`,TWN:`所以，這次我讓步。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};